// MARK: - Data Security Errors

enum DataSecurityError: Error, LocalizedError {
    case keyGenerationFailed
    case keychainSaveFailed(OSStatus)
    case keychainReadFailed(OSStatus)
    case keychainDeleteFailed(OSStatus)
    case encryptionFailed(CCCryptorStatus)
    case decryptionFailed(CCCryptorStatus)
    case invalidData
    case invalidKey
    case dataEncodingFailed
    case dataDecodingFailed
    
    var errorDescription: String? {
        switch self {
        case .keyGenerationFailed: return "Failed to generate encryption key"
        case .keychainSaveFailed(let status): return "Keychain save failed: \(status)"
        case .keychainReadFailed(let status): return "Keychain read failed: \(status)"
        case .keychainDeleteFailed(let status): return "Keychain delete failed: \(status)"
        case .encryptionFailed(let status): return "Encryption failed: \(status)"
        case .decryptionFailed(let status): return "Decryption failed: \(status)"
        case .invalidData: return "Invalid data provided"
        case .invalidKey: return "Invalid encryption key"
        case .dataEncodingFailed: return "Failed to encode data"
        case .dataDecodingFailed: return "Failed to decode data"
        }
    }
}

