// MARK: - Keychain Manager

final class KeychainManager {
    
    static let shared = KeychainManager()
    
    private let serviceName = "com.app.datasecurity"
    private let encryptionKeyAccount = "encryption_master_key"
    
    private init() {}
    
    func saveKey(_ keyData: Data) throws {
        // Delete existing key first
        try? deleteKey()
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw DataSecurityError.keychainSaveFailed(status)
        }
    }
    
    func readKey() throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let keyData = result as? Data else {
            throw DataSecurityError.keychainReadFailed(status)
        }
        
        return keyData
    }
    
    func deleteKey() throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw DataSecurityError.keychainDeleteFailed(status)
        }
    }
    
    func keyExists() -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecReturnData as String: false,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }
}

// MARK: - AES Encryption Engine

final class AESEncryptionEngine {
    
    static let keySize = kCCKeySizeAES256
    static let blockSize = kCCBlockSizeAES128
    static let ivSize = kCCBlockSizeAES128
    
    // MARK: - Key Generation
    
    static func generateKey() throws -> Data {
        var keyData = Data(count: keySize)
        let result = keyData.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, keySize, bytes.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return keyData
    }
    
    // MARK: - IV Generation
    
    static func generateIV() throws -> Data {
        var ivData = Data(count: ivSize)
        let result = ivData.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, ivSize, bytes.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return ivData
    }
    
    // MARK: - Encryption
    
    static func encrypt(data: Data, key: Data) throws -> Data {
        guard key.count == keySize else {
            throw DataSecurityError.invalidKey
        }
        
        let iv = try generateIV()
        
        let bufferSize = data.count + blockSize
        var encryptedData = Data(count: bufferSize)
        var encryptedLength: Int = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                data.withUnsafeBytes { dataBytes in
                    encryptedData.withUnsafeMutableBytes { encryptedBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress,
                            keySize,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress,
                            data.count,
                            encryptedBytes.baseAddress,
                            bufferSize,
                            &encryptedLength
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.encryptionFailed(status)
        }
        
        encryptedData.count = encryptedLength
        
        // Prepend IV to encrypted data so we can use it for decryption
        var result = iv
        result.append(encryptedData)
        return result
    }
    
    // MARK: - Decryption
    
    static func decrypt(data: Data, key: Data) throws -> Data {
        guard key.count == keySize else {
            throw DataSecurityError.invalidKey
        }
        
        guard data.count > ivSize else {
            throw DataSecurityError.invalidData
        }
        
        // Extract IV from the beginning of the data
        let iv = data.prefix(ivSize)
        let encryptedData = data.suffix(from: ivSize)
        
        let bufferSize = encryptedData.count + blockSize
        var decryptedData = Data(count: bufferSize)
        var decryptedLength: Int = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                encryptedData.withUnsafeBytes { encryptedBytes in
                    decryptedData.withUnsafeMutableBytes { decryptedBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress,
                            keySize,
                            ivBytes.baseAddress,
                            encryptedBytes.baseAddress,
                            encryptedData.count,
                            decryptedBytes.baseAddress,
                            bufferSize,
                            &decryptedLength
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.decryptionFailed(status)
        }
        
        decryptedData.count = decryptedLength
        return decryptedData
    }
}

// MARK: - Secure Local Storage

final class SecureLocalStorage {
    
    static let shared = SecureLocalStorage()
    
    private let fileManager = FileManager.default
    private let storageQueue = DispatchQueue(label: "com.app.securestorage", qos: .userInitiated)
    
    private var secureDirectoryURL: URL {
        let documentsURL = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        let secureDir = documentsURL.appendingPathComponent("SecureData", isDirectory: true)
        if !fileManager.fileExists(atPath: secureDir.path) {
            try? fileManager.createDirectory(at: secureDir, withIntermediateDirectories: true)
        }
        // Exclude from backups
        var resourceValues = URLResourceValues()
        resourceValues.isExcludedFromBackup = true
        var mutableURL = secureDir
        try? mutableURL.setResourceValues(resourceValues)
        return secureDir
    }
    
    private init() {}
    
    func saveEncryptedData(_ data: Data, forKey key: String) throws {
        let fileURL = secureDirectoryURL.appendingPathComponent(key.sha256Hash)
        try data.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func readEncryptedData(forKey key: String) throws -> Data {
        let fileURL = secureDirectoryURL.appendingPathComponent(key.sha256Hash)
        guard fileManager.fileExists(atPath: fileURL.path) else {
            throw DataSecurityError.invalidData
        }
        return try Data(contentsOf: fileURL)
    }
    
    func deleteEncryptedData(forKey key: String) throws {
        let fileURL = secureDirectoryURL.appendingPathComponent(key.sha256Hash)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
    
    func deleteAllSecureData() throws {
        if fileManager.fileExists(atPath: secureDirectoryURL.path) {
            try fileManager.removeItem(at: secureDirectoryURL)
        }
    }
}

// MARK: - String SHA256 Extension

extension String {
    var sha256Hash: String {
        let data = Data(self.utf8)
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { bytes in
            _ = CC_SHA256(bytes.baseAddress, CC_LONG(data.count), &hash)
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}

