final class DataSecurityModule {
    
    static let shared = DataSecurityModule()
    
    private let keychainManager = KeychainManager.shared
    private let secureStorage = SecureLocalStorage.shared
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()
    
    private let operationQueue = DispatchQueue(label: "com.app.datasecurity.operations", qos: .userInitiated)
    
    private init() {
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601
    }
    
    // MARK: - Initialization
    
    /// Initialize the module - generates and stores a key in Keychain if one doesn't exist
    func initialize() throws {
        if !keychainManager.keyExists() {
            let key = try AESEncryptionEngine.generateKey()
            try keychainManager.saveKey(key)
        }
    }
    
    /// Retrieve the encryption key from Keychain
    private func getEncryptionKey() throws -> Data {
        return try keychainManager.readKey()
    }
    
    // MARK: - Generic Encrypt / Decrypt
    
    func encrypt<T: Encodable>(_ object: T) throws -> Data {
        let key = try getEncryptionKey()
        let jsonData = try encoder.encode(object)
        let encryptedData = try AESEncryptionEngine.encrypt(data: jsonData, key: key)
        return encryptedData
    }
    
    func decrypt<T: Decodable>(_ type: T.Type, from data: Data) throws -> T {
        let key = try getEncryptionKey()
        let decryptedData = try AESEncryptionEngine.decrypt(data: data, key: key)
        let object = try decoder.decode(type, from: decryptedData)
        return object
    }
    
    // MARK: - Raw Data Encrypt / Decrypt
    
    func encryptRawData(_ data: Data) throws -> Data {
        let key = try getEncryptionKey()
        return try AESEncryptionEngine.encrypt(data: data, key: key)
    }
    
    func decryptRawData(_ encryptedData: Data) throws -> Data {
        let key = try getEncryptionKey()
        return try AESEncryptionEngine.decrypt(data: encryptedData, key: key)
    }
    
    // MARK: - String Encrypt / Decrypt
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw DataSecurityError.dataEncodingFailed
        }
        return try encryptRawData(data)
    }
    
    func decryptString(from encryptedData: Data) throws -> String {
        let data = try decryptRawData(encryptedData)
        guard let string = String(data: data, encoding: .utf8) else {
            throw DataSecurityError.dataDecodingFailed
        }
        return string
    }
    
    // MARK: - User Credentials
    
