    func wipeAllSecureData() throws {
        try secureStorage.deleteAllSecureData()
    }
    
    /// Full reset - wipes all data AND removes encryption key
    func fullReset() throws {
        try secureStorage.deleteAllSecureData()
        try keychainManager.deleteKey()
    }
    
    // MARK: - Key Rotation
    
    /// Rotates the encryption key. Re-encrypts all stored data with a new key.
    /// Provide the storage keys for all data that needs re-encryption.
    func rotateEncryptionKey(dataKeys: [String]) throws {
        let oldKey = try getEncryptionKey()
        let newKey = try AESEncryptionEngine.generateKey()
        
        // Re-encrypt all existing data
        var reEncryptedData: [(String, Data)] = []
        
        for dataKey in dataKeys {
            do {
                let encryptedData = try secureStorage.readEncryptedData(forKey: dataKey)
                let decryptedData = try AESEncryptionEngine.decrypt(data: encryptedData, key: oldKey)
                let newEncryptedData = try AESEncryptionEngine.encrypt(data: decryptedData, key: newKey)
                reEncryptedData.append((dataKey, newEncryptedData))
            } catch DataSecurityError.invalidData {
                // Key doesn't exist, skip
                continue
            }
        }
        
        // Save new key
        try keychainManager.saveKey(newKey)
        
        // Save re-encrypted data
        for (dataKey, data) in reEncryptedData {
            try secureStorage.saveEncryptedData(data, forKey: dataKey)
        }
    }
